@section('scripts')<script>window.adicionarLinhaRegra=function(button){const c=button.closest('.box').querySelector('.regras-container');const i=c.querySelectorAll('.regra-item').length;c.insertAdjacentHTML('beforeend',`<div class="row regra-item align-items-end mb-2"><div class="col-md-5"><label class="form-label">Tipo</label><select name="regras[${i}][regra_tipo]" class="form-control"><option value="cargo">Cargo</option><option value="filial">Filial</option><option value="setor">Setor</option></select></div><div class="col-md-5"><label class="form-label">Referência</label><input type="number" min="1" class="form-control" name="regras[${i}][referencia_id]"></div><div class="col-md-2"><button type="button" class="btn btn-danger btn-sm" onclick="this.closest('.regra-item').remove()">Remover</button></div></div>`);};window.adicionarLinhaOpcao=function(button){const c=button.closest('.box').querySelector('.opcoes-container');const i=c.querySelectorAll('.opcao-item').length;c.insertAdjacentHTML('beforeend',`<div class="row opcao-item align-items-end mb-2"><div class="col-md-5"><label class="form-label">Texto</label><input type="text" class="form-control" name="opcoes[${i}][texto]"></div><div class="col-md-3"><label class="form-label">Valor</label><input type="text" class="form-control" name="opcoes[${i}][valor]"></div><div class="col-md-2"><label class="form-label">Ordem</label><input type="number" class="form-control" name="opcoes[${i}][ordem]" value="${i+1}"></div><div class="col-md-1"><label class="form-label">Ativa</label><select class="form-control" name="opcoes[${i}][ativa]"><option value="1">Sim</option><option value="0">Não</option></select></div><div class="col-md-1"><button type="button" class="btn btn-danger btn-sm" onclick="this.closest('.opcao-item').remove()">X</button></div></div>`);};</script>@endsection
